/** Find a design system by slug (exact) or name (case-insensitive substring). */
export function findDesignSystem(query: string): DesignSystem | undefined {
  const q = query.trim().toLowerCase();
  if (designSystems[q]) return designSystems[q];
  // Fuzzy: match slug containing query or name containing query
  return Object.values(designSystems).find(
    (d) => d.slug.includes(q) || d.name.toLowerCase().includes(q),
  );
}
